code = """import json
from datetime import datetime

# Load data from previous tool results
business_json_path = var_call_MVrHICHYGcNCpZVKMBLyi3Uh
with open(business_json_path, 'r', encoding='utf-8') as f:
    businesses = json.load(f)
reviews = var_call_cRMlCVbNICaZ2eyMXuObpfUo

# Build review mapping
review_map = {r['gmap_id']: float(r['avg_rating']) for r in reviews}

# Helper to parse time like '9AM' or '9:30PM'
def parse_time(t):
    t = t.strip().upper()
    # handle missing AM/PM? assume always present
    if t == '':
        return None
    # Remove periods if any
    t = t.replace('.', '')
    # Find AM/PM
    if t.endswith('AM') or t.endswith('PM'):
        ampm = t[-2:]
        core = t[:-2]
    else:
        return None
    core = core.strip()
    if ':' in core:
        h, m = core.split(':')
        try:
            h = int(h)
            m = int(m)
        except:
            return None
    else:
        try:
            h = int(core)
            m = 0
        except:
            return None
    if ampm == 'AM':
        if h == 12:
            h = 0
    else:  # PM
        if h != 12:
            h += 12
    return h*60 + m

weekdays = set(['Monday','Tuesday','Wednesday','Thursday','Friday'])

candidates = []
for b in businesses:
    gid = b.get('gmap_id')
    hours_str = b.get('hours')
    if not hours_str or hours_str in (None, 'None'):
        continue
    # hours_str expected to be JSON list string
    try:
        hours_list = json.loads(hours_str)
    except Exception:
        # skip if cannot parse
        continue
    open_after_6 = False
    # hours_list may contain entries like [ ["Thursday","6:30AM–6PM"], ... ]
    for entry in hours_list:
        if not isinstance(entry, (list, tuple)) or len(entry) < 2:
            continue
        day = entry[0]
        times = entry[1]
        if day not in weekdays:
            continue
        if not times or 'closed' in times.lower():
            continue
        # split on dash or en-dash
        import re
        parts = re.split(r"[-–—]\s*", times)
        if len(parts) < 2:
            continue
        start, end = parts[0].strip(), parts[1].strip()
        end_minutes = parse_time(end)
        if end_minutes is None:
            continue
        if end_minutes > 18*60:  # strictly after 6:00 PM
            open_after_6 = True
            break
    if open_after_6 and gid in review_map:
        candidates.append({
            'gmap_id': gid,
            'name': b.get('name'),
            'hours': hours_str,
            'avg_rating': review_map[gid]
        })

# Sort by avg_rating desc
candidates_sorted = sorted(candidates, key=lambda x: (-x['avg_rating'], x['name']))
top5 = candidates_sorted[:5]
# Round avg_rating to 3 decimals for readability
for item in top5:
    item['avg_rating'] = round(item['avg_rating'], 3)

result = json.dumps(top5)
print("__RESULT__:")
print(result)"""

